// ─── CONFIG (never commit real key) ──────────────────────────────────────────
const CONFIG = {
  CLAUDE_API_KEY: "sk-ant-YOUR-KEY-HERE", // replace before use; add src/config.js to .gitignore
};

// ─── CONSTANTS ────────────────────────────────────────────────────────────────
const ROLE_MECH_BASE = "Mechanic (BASE)";
const ROLE_PORTER = "Porter";
const ROLE_MECH_AUTO = "Mechanic (AUTO)"; // accepted in RawData, excluded everywhere else

const COL = {
  // 0-based indices for RawData columns A–J
  REGION: 0,
  ROLE: 1,
  NAME: 2,
  PPE_DATE: 3,
  ST: 4,
  OT: 5,
  DT: 6,
  ST_PAY: 7,
  OT_PAY: 8,
  DT_PAY: 9,
};

