// ─── STEP 8: PORTER EXPENSE BY REGION ────────────────────────────────────────
export async function buildPorterExpenseByRegion(filteredData) {
  const groups = groupByRegion(filteredData, ROLE_PORTER, "expense");
  await writeRegionTable(
    groups,
    "G20",
    ["Region", "ST Pay", "OT Pay", "DT Pay", "Total Pay"],
    "expense"
  );
}

function groupByRegion(data, role, type) {
  const filtered = data.filter((r) => r.role === role);
  const map = {};
  for (const r of filtered) {
    const key = r.region || "(No Region)";
    if (!map[key]) map[key] = { region: key, st: 0, ot: 0, dt: 0 };
    if (type === "hours") {
      map[key].st += r.st;
      map[key].ot += r.ot;
      map[key].dt += r.dt;
    } else {
      map[key].st += r.stPay;
      map[key].ot += r.otPay;
      map[key].dt += r.dtPay;
    }
  }
  return Object.values(map).sort((a, b) => a.region.localeCompare(b.region));
}

async function writeRegionTable(groups, startCell, headers, type) {
  await Excel.run(async (context) => {
    const sheet = context.workbook.worksheets.getItem("Dashboard");

    // Parse start cell to get column letters
    const colLetters = startCell.replace(/[0-9]/g, "");
    const startRow = parseInt(startCell.replace(/[A-Z]/gi, ""), 10);
    const cols = expandColumns(colLetters, 5);

    const headerRange = sheet.getRange(`${cols[0]}${startRow}:${cols[4]}${startRow}`);
    headerRange.values = [headers];
    headerRange.format.font.bold = true;
    headerRange.format.fill.color = "#1F3864";
    headerRange.format.font.color = "white";

    // Clear old data below header (up to 50 rows)
    if (groups.length < 50) {
      const clearRange = sheet.getRange(`${cols[0]}${startRow + 1}:${cols[4]}${startRow + 50}`);
      clearRange.clear();
    }

    if (groups.length === 0) {
      const emptyRange = sheet.getRange(`${cols[0]}${startRow + 1}`);
      emptyRange.values = [["No data"]];
      await context.sync();
      return;
    }

    const dataRows = groups.map((g) => [g.region, g.st, g.ot, g.dt, g.st + g.ot + g.dt]);
    const dataRange = sheet.getRange(
      `${cols[0]}${startRow + 1}:${cols[4]}${startRow + groups.length}`
    );
    dataRange.values = dataRows;

    // Alternating row shading
    for (let i = 0; i < groups.length; i++) {
      const rowRange = sheet.getRange(
        `${cols[0]}${startRow + 1 + i}:${cols[4]}${startRow + 1 + i}`
      );
      rowRange.format.fill.color = i % 2 === 0 ? "#EBF3FB" : "white";
    }

    // Format pay columns individually if expense
    if (type === "expense") {
      for (let i = 1; i <= 4; i++) {
        sheet.getRange(
          `${cols[i]}${startRow + 1}:${cols[i]}${startRow + groups.length}`
        ).numberFormat = [["$#,##0.00"]];
      }
    }

    await context.sync();
  });
}

// ─── FILTER LOGIC ─────────────────────────────────────────────────────────────
let _allData = []; // cached full dataset (Mechanic Auto excluded)

export function applyFilter(allData, filterType, filterValue) {
  // Always exclude Mechanic Auto
  const base = allData.filter((r) => r.role !== ROLE_MECH_AUTO);

  if (filterType === "All Time" || !filterValue) return base;

  return base.filter((r) => {
    const d = r.ppeDate;
    if (filterType === "Week") {
      return d.getTime() === new Date(filterValue).getTime();
    }
    if (filterType === "Month") {
      // filterValue format: "Jan 2026"
      const [mon, yr] = filterValue.split(" ");
      const monthIndex = [
        "Jan",
        "Feb",
        "Mar",
        "Apr",
        "May",
        "Jun",
        "Jul",
        "Aug",
        "Sep",
        "Oct",
        "Nov",
        "Dec",
      ].indexOf(mon);
      return d.getFullYear() === parseInt(yr, 10) && d.getMonth() === monthIndex;
    }
    if (filterType === "Year") {
      return d.getFullYear() === parseInt(filterValue, 10);
    }
    return true;
  });
}

export function populateFilterDropdowns(allData) {
  const base = allData.filter((r) => r.role !== ROLE_MECH_AUTO);
  const filterType = document.getElementById("filterType");
  const filterValue = document.getElementById("filterValue");

  const type = filterType ? filterType.value : "All Time";

  if (type === "All Time") {
    if (filterValue) filterValue.style.display = "none";
    return;
  }
  if (filterValue) filterValue.style.display = "inline-block";

  let options = [];
  if (type === "Week") {
    const dates = [...new Set(base.map((r) => r.ppeDate.getTime()))].sort((a, b) => b - a);
    options = dates.map((t) => {
      const d = new Date(t);
      return { label: formatDate(d), value: d.toISOString() };
    });
  } else if (type === "Month") {
    const months = [
      ...new Set(
        base.map((r) => {
          const d = r.ppeDate;
          return `${["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"][d.getMonth()]} ${d.getFullYear()}`;
        })
      ),
    ]
      .sort()
      .reverse();
    options = months.map((m) => ({ label: m, value: m }));
  } else if (type === "Year") {
    const years = [...new Set(base.map((r) => r.ppeDate.getFullYear()))].sort((a, b) => b - a);
    options = years.map((y) => ({ label: String(y), value: String(y) }));
  }

  if (filterValue) {
    filterValue.innerHTML = "";
    for (const opt of options) {
      const el = document.createElement("option");
      el.value = opt.value;
      el.textContent = opt.label;
      filterValue.appendChild(el);
    }
  }
}

function onFilterTypeChange() {
  populateFilterDropdowns(_allData);
  runDashboardUpdate();
}

function onFilterValueChange() {
  runDashboardUpdate();
}

async function runDashboardUpdate() {
  const filterType = document.getElementById("filterType")?.value || "All Time";
  const filterValue = document.getElementById("filterValue")?.value || "";
  const filtered = applyFilter(_allData, filterType, filterValue);

  await buildKpiCards(filtered);
  await buildTopPerformersBanner(filtered);
  await buildMechBaseHoursByRegion(filtered);
  await buildMechBaseExpenseByRegion(filtered);
  await buildPorterHoursByRegion(filtered);
  await buildPorterExpenseByRegion(filtered);
}

// ─── STEP 16: REFRESH ALL ─────────────────────────────────────────────────────
export async function refreshAll() {
  setLoading(true);

  try {
    // Ensure sheets exist
    await createRawDataSheet();
    await createDashboardShell();

    // Read raw data
    let allData = [];
    await Excel.run(async (context) => {
      allData = await readRawData(context);
    });

    // Exclude Mechanic Auto everywhere
    _allData = allData.filter((r) => r.role !== ROLE_MECH_AUTO);

    if (_allData.length === 0) {
      showMessage("No data found. Please add rows to RawData.");
      setLoading(false);
      return;
    }

    // Rebuild pivot sheets
    await buildMechanicBasePivot();
    await buildPortersPivot();

    // Populate filter dropdowns
    populateFilterDropdowns(_allData);

    // Apply current filter
    const filterType = document.getElementById("filterType")?.value || "All Time";
    const filterValue = document.getElementById("filterValue")?.value || "";
    const filtered = applyFilter(_allData, filterType, filterValue);

    // Dashboard sections
    await buildKpiCards(filtered);
    await buildTopPerformersBanner(filtered);
    await buildMechBaseHoursByRegion(filtered);
    await buildMechBaseExpenseByRegion(filtered);
    await buildPorterHoursByRegion(filtered);
    await buildPorterExpenseByRegion(filtered);

    // Charts use full unfiltered data (always show all weeks/months)
    await buildWeeklyStackedBarChart(_allData);
    await buildYearOverYearChart(_allData);

    // AI Insights
    const summaryData = buildSummaryData(filtered, _allData);
    const insights = await getAiInsights(summaryData);
    await writeInsightsToDashboard(insights);
    updateInsightsPane(insights);

    showToast(`Dashboard updated — ${new Date().toLocaleTimeString()}`);
  } catch (err) {
    console.error("refreshAll error:", err);
    showMessage(`Error: ${err.message}`);
  } finally {
    setLoading(false);
  }
}

// ─── STEP 11: STACKED BAR — TOTAL HOURS PER WEEK ─────────────────────────────
export async function buildWeeklyStackedBarChart(allData) {
  // Filter out Mechanic Auto
  const base = allData.filter((r) => r.role !== ROLE_MECH_AUTO);

  // Group by PPE Date week
  const weekMap = {};
  for (const r of base) {
    const key = r.ppeDate.getTime();
    if (!weekMap[key]) weekMap[key] = { ppeDate: r.ppeDate, mechBaseHours: 0, porterHours: 0 };
    if (r.role === ROLE_MECH_BASE) weekMap[key].mechBaseHours += r.st + r.ot + r.dt;
    if (r.role === ROLE_PORTER) weekMap[key].porterHours += r.st + r.ot + r.dt;
  }
  const weeks = Object.values(weekMap).sort((a, b) => a.ppeDate - b.ppeDate);

  await Excel.run(async (context) => {
    const sheets = context.workbook.worksheets;
    sheets.load("items/name");
    await context.sync();

    // Write to Charts_Data helper sheet (columns A–C)
    let chartsSheet;
    const chartsExists = sheets.items.some((s) => s.name === "Charts_Data");
    if (chartsExists) {
      chartsSheet = sheets.getItem("Charts_Data");
      chartsSheet.getRange("A1:C200").clear();
    } else {
      chartsSheet = sheets.add("Charts_Data");
    }

    const cdHeaders = [["PPE Date", "Mech BASE Hours", "Porter Hours"]];
    chartsSheet.getRange("A1:C1").values = cdHeaders;
    chartsSheet.getRange("A1:C1").format.font.bold = true;

    if (weeks.length > 0) {
      const cdRows = weeks.map((w) => [
        dateToExcelSerial(w.ppeDate),
        w.mechBaseHours,
        w.porterHours,
      ]);
      const cdRange = chartsSheet.getRange(`A2:C${1 + cdRows.length}`);
      cdRange.values = cdRows;
      chartsSheet.getRange(`A2:A${1 + cdRows.length}`).numberFormat = [["mm/dd/yyyy"]];
    }

    // Create / replace chart on Dashboard
    const dashSheet = context.workbook.worksheets.getItem("Dashboard");
    const existingCharts = dashSheet.charts;
    existingCharts.load("items/name");
    await context.sync();

    // Remove old weekly chart if present
    const oldChart = existingCharts.items.find((c) => c.name === "WeeklyHoursChart");
    if (oldChart) oldChart.delete();

    if (weeks.length === 0) {
      await context.sync();
      return;
    }

    // Data source range from Charts_Data
    const dataRange = chartsSheet.getRange(`A1:C${1 + weeks.length}`);
    const chart = dashSheet.charts.add(
      Excel.ChartType.barStacked,
      dataRange,
      Excel.ChartSeriesBy.columns
    );
    chart.name = "WeeklyHoursChart";
    chart.title.text = "Total Hours Per Week";
    chart.title.visible = true;
    chart.setPosition(dashSheet.getRange("A32"), dashSheet.getRange("F48"));

    // Series colors
    chart.series.load("items");
    await context.sync();
    if (chart.series.items.length >= 1) chart.series.items[0].format.fill.setSolidColor("#1F3864");
    if (chart.series.items.length >= 2) chart.series.items[1].format.fill.setSolidColor("#808080");

    await context.sync();
  });

  // Also update mini chart in task pane
  updateMiniChart(weeks);
}

// ─── STEP 12: GROUPED BAR — THIS MONTH VS SAME MONTH LAST YEAR ───────────────
export async function buildYearOverYearChart(allData) {
  const base = allData.filter((r) => r.role !== ROLE_MECH_AUTO);

  const now = new Date();
  const currentMonth = now.getMonth();
  const currentYear = now.getFullYear();
  const lastYear = currentYear - 1;

  const monthNames = [
    "Jan",
    "Feb",
    "Mar",
    "Apr",
    "May",
    "Jun",
    "Jul",
    "Aug",
    "Sep",
    "Oct",
    "Nov",
    "Dec",
  ];
  const currentLabel = `${monthNames[currentMonth]} ${currentYear}`;
  const lastYearLabel = `${monthNames[currentMonth]} ${lastYear}`;

  function sumForPeriod(role, year, month) {
    const rows = base.filter(
      (r) => r.role === role && r.ppeDate.getFullYear() === year && r.ppeDate.getMonth() === month
    );
    return {
      hours: rows.reduce((s, r) => s + r.st + r.ot + r.dt, 0),
      expense: rows.reduce((s, r) => s + r.stPay + r.otPay + r.dtPay, 0),
    };
  }

  const mechCurrent = sumForPeriod(ROLE_MECH_BASE, currentYear, currentMonth);
  const porterCurrent = sumForPeriod(ROLE_PORTER, currentYear, currentMonth);
  const mechLastYear = sumForPeriod(ROLE_MECH_BASE, lastYear, currentMonth);
  const porterLastYear = sumForPeriod(ROLE_PORTER, lastYear, currentMonth);

  await Excel.run(async (context) => {
    const sheets = context.workbook.worksheets;
    sheets.load("items/name");
    await context.sync();

    let chartsSheet;
    const chartsExists = sheets.items.some((s) => s.name === "Charts_Data");
    if (chartsExists) {
      chartsSheet = sheets.getItem("Charts_Data");
    } else {
      chartsSheet = sheets.add("Charts_Data");
    }

    // Write YoY data starting at column H
    chartsSheet.getRange("H1:K1").values = [["Period", "Role", "Total Hours", "Total Expense"]];
    chartsSheet.getRange("H1:K1").format.font.bold = true;

    const yoyRows = [
      [`${currentLabel}`, ROLE_MECH_BASE, mechCurrent.hours, mechCurrent.expense],
      [`${currentLabel}`, ROLE_PORTER, porterCurrent.hours, porterCurrent.expense],
      [`${lastYearLabel}`, ROLE_MECH_BASE, mechLastYear.hours, mechLastYear.expense],
      [`${lastYearLabel}`, ROLE_PORTER, porterLastYear.hours, porterLastYear.expense],
    ];
    chartsSheet.getRange("H2:K5").values = yoyRows;

    // Build chart data: categories = roles, series = This Year / Last Year
    // Layout for grouped bar: rows=categories(Mech BASE, Porter), cols=series(This Yr, Last Yr)
    chartsSheet.getRange("N1:P1").values = [["Role", currentLabel, lastYearLabel]];
    chartsSheet.getRange("N2:P3").values = [
      [ROLE_MECH_BASE, mechCurrent.hours, mechLastYear.hours],
      [ROLE_PORTER, porterCurrent.hours, porterLastYear.hours],
    ];
    chartsSheet.getRange("N1:P1").format.font.bold = true;

    // Remove old YoY chart if present
    const dashSheet = context.workbook.worksheets.getItem("Dashboard");
    const existingCharts = dashSheet.charts;
    existingCharts.load("items/name");
    await context.sync();

    const oldChart = existingCharts.items.find((c) => c.name === "YearOverYearChart");
    if (oldChart) oldChart.delete();

    const chartDataRange = chartsSheet.getRange("N1:P3");
    const chart = dashSheet.charts.add(
      Excel.ChartType.barClustered,
      chartDataRange,
      Excel.ChartSeriesBy.columns
    );
    chart.name = "YearOverYearChart";
    chart.title.text = `This Month vs Same Month Last Year (${monthNames[currentMonth]})`;
    chart.title.visible = true;
    chart.setPosition(dashSheet.getRange("G32"), dashSheet.getRange("M48"));

    chart.series.load("items");
    await context.sync();
    // This Year series: solid blue/gray; Last Year: lighter tints
    if (chart.series.items.length >= 1) chart.series.items[0].format.fill.setSolidColor("#1F3864"); // Mech BASE this yr
    if (chart.series.items.length >= 2) chart.series.items[1].format.fill.setSolidColor("#A8C3E3"); // Mech BASE last yr

    await context.sync();
  });
}

// ─── STEP 15: AI INSIGHTS ────────────────────────────────────────────────────
export async function getAiInsights(summaryData) {
  const apiKey = CONFIG.CLAUDE_API_KEY;
  if (!apiKey || apiKey.includes("YOUR-KEY")) {
    return {
      summary: "AI Insights unavailable — no API key configured.",
      impact: "Set CONFIG.CLAUDE_API_KEY in src/taskpane/taskpane.js.",
      forecast: "",
    };
  }

  const {
    currentPeriodLabel,
    mechBaseHours,
    mechBaseExpense,
    porterHours,
    porterExpense,
    topMechBase,
    topPorter,
    priorMechBaseHours,
    priorPorterHours,
    regionBreakdown,
    percentChangeHours,
  } = summaryData;

  const regionText = (regionBreakdown || [])
    .map(
      (r) =>
        `${r.region}: Mech BASE ${Math.round(r.mechBaseHours)} hrs, Porter ${Math.round(r.porterHours)} hrs`
    )
    .join("; ");

  const userPrompt =
    `Period: ${currentPeriodLabel}\n` +
    `Mechanic BASE — Hours: ${Math.round(mechBaseHours)}, Expense: $${Math.round(mechBaseExpense).toLocaleString()}\n` +
    `Porter — Hours: ${Math.round(porterHours)}, Expense: $${Math.round(porterExpense).toLocaleString()}\n` +
    `Top Mechanic BASE: ${topMechBase ? `${topMechBase.name} (${Math.round(topMechBase.hours)} hrs)` : "N/A"}\n` +
    `Top Porter: ${topPorter ? `${topPorter.name} (${Math.round(topPorter.hours)} hrs)` : "N/A"}\n` +
    `Prior period — Mech BASE Hours: ${Math.round(priorMechBaseHours)}, Porter Hours: ${Math.round(priorPorterHours)}\n` +
    `Total hours change vs prior: ${percentChangeHours >= 0 ? "+" : ""}${Math.round(percentChangeHours)}%\n` +
    `Region breakdown: ${regionText || "N/A"}\n\n` +
    `Provide exactly 3 labeled sections:\n` +
    `SUMMARY: (what changed this period vs prior)\n` +
    `IMPACT: (which region or role is driving the change)\n` +
    `FORECAST: (data-based prediction for next period)\n` +
    `Keep total response under 200 words. Plain text only, no markdown.`;

  try {
    const response = await fetch("https://api.anthropic.com/v1/messages", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "x-api-key": apiKey,
        "anthropic-version": "2023-06-01",
        "anthropic-dangerous-direct-browser-access": "true",
      },
      body: JSON.stringify({
        model: "claude-sonnet-4-6",
        max_tokens: 300,
        system:
          "You are a workforce analytics assistant. Provide a concise 3-part insight " +
          "(under 200 words total) based on overtime data for Mechanic BASE and Porter " +
          "roles only. Use plain language, no markdown headers.",
        messages: [{ role: "user", content: userPrompt }],
      }),
    });

    if (!response.ok) {
      const err = await response.text();
      throw new Error(`API error ${response.status}: ${err}`);
    }

    const data = await response.json();
    const text = data.content?.[0]?.text || "";

    // Parse the 3 sections
    const parse = (label) => {
      const re = new RegExp(`${label}:\\s*([\\s\\S]*?)(?=SUMMARY:|IMPACT:|FORECAST:|$)`, "i");
      const match = text.match(re);
      return match ? match[1].trim() : "";
    };

    return {
      summary: parse("SUMMARY"),
      impact: parse("IMPACT"),
      forecast: parse("FORECAST"),
    };
  } catch (err) {
    console.error("AI Insights error:", err);
    return {
      summary: `Could not fetch insights: ${err.message}`,
      impact: "",
      forecast: "",
    };
  }
}

async function writeInsightsToDashboard({ summary, impact, forecast }) {
  await Excel.run(async (context) => {
    const sheet = context.workbook.worksheets.getItem("Dashboard");

    // Header
    const headerRange = sheet.getRange("A50:M50");
    headerRange.merge(false);
    headerRange.values = [["AI INSIGHTS"]];
    headerRange.format.font.bold = true;
    headerRange.format.font.size = 12;
    headerRange.format.font.color = "white";
    headerRange.format.fill.color = "#1F3864";
    headerRange.format.horizontalAlignment = Excel.HorizontalAlignment.left;

    const writeRow = (row, label, text) => {
      const labelCell = sheet.getRange(`A${row}`);
      labelCell.values = [[label]];
      labelCell.format.font.bold = true;
      labelCell.format.font.color = "#1F3864";

      const textRange = sheet.getRange(`B${row}:M${row}`);
      textRange.merge(false);
      textRange.values = [[text]];
      textRange.format.wrapText = true;
      textRange.format.rowHeight = 48;
    };

    writeRow(51, "SUMMARY:", summary || "—");
    writeRow(52, "IMPACT:", impact || "—");
    writeRow(53, "FORECAST:", forecast || "—");

    await context.sync();
  });
}

