function buildSummaryData(filteredData, allData) {
  const priorData = computePriorPeriod(allData);

  const regionMap = {};
  for (const r of filteredData.filter((row) => row.role !== ROLE_MECH_AUTO)) {
    if (!regionMap[r.region])
      regionMap[r.region] = { region: r.region, mechBaseHours: 0, porterHours: 0 };
    if (r.role === ROLE_MECH_BASE) regionMap[r.region].mechBaseHours += r.st + r.ot + r.dt;
    if (r.role === ROLE_PORTER) regionMap[r.region].porterHours += r.st + r.ot + r.dt;
  }

  const mechBaseHours = sumHours(filteredData, ROLE_MECH_BASE);
  const porterHours = sumHours(filteredData, ROLE_PORTER);
  const totalHours = mechBaseHours + porterHours;
  const priorTotal = priorData.mechBaseHours + priorData.porterHours;
  const percentChange = priorTotal > 0 ? ((totalHours - priorTotal) / priorTotal) * 100 : 0;

  const filterType = document.getElementById("filterType")?.value || "All Time";
  const filterValue = document.getElementById("filterValue")?.value || "";
  const label =
    filterType === "All Time"
      ? "All Time"
      : filterType === "Week"
        ? `Week of ${filterValue}`
        : filterValue;

  return {
    currentPeriodLabel: label,
    mechBaseHours,
    mechBaseExpense: sumExpense(filteredData, ROLE_MECH_BASE),
    porterHours,
    porterExpense: sumExpense(filteredData, ROLE_PORTER),
    topMechBase: findTopPerformer(filteredData, ROLE_MECH_BASE),
    topPorter: findTopPerformer(filteredData, ROLE_PORTER),
    priorMechBaseHours: priorData.mechBaseHours,
    priorPorterHours: priorData.porterHours,
    regionBreakdown: Object.values(regionMap),
    percentChangeHours: percentChange,
  };
}

function computePriorPeriod(allData) {
  // Find the second-most-recent PPE week as "prior period" when no filter is active
  const base = allData.filter((r) => r.role !== ROLE_MECH_AUTO);
  const weeks = [...new Set(base.map((r) => r.ppeDate.getTime()))].sort((a, b) => b - a);
  if (weeks.length < 2) return { mechBaseHours: 0, porterHours: 0 };

  const priorWeekTs = weeks[1];
  const priorRows = base.filter((r) => r.ppeDate.getTime() === priorWeekTs);
  return {
    mechBaseHours: sumHours(priorRows, ROLE_MECH_BASE),
    porterHours: sumHours(priorRows, ROLE_PORTER),
  };
}

